// Nimmt die Trigger-Payload (Webhook/Formular) entgegen und normalisiert die fuer die
// Rechnung noetigen Felder. Fehlende Felder bleiben leer -> 'KI: Rechnungstext formatieren'
// erfindet nichts dazu, sondern laesst die Position offen.
const b = $json.body || $json || {};
return [{
  json: {
    kunde_name: b.kunde_name || b.customer || '',
    kunde_email: b.kunde_email || b.email || '',
    leistung: b.leistung || b.service || '',
    betrag_hinweis: b.betrag || b.amount || '',
    faelligkeit_tage: Number(b.faelligkeit_tage || 14),
  },
}];

// Sicheres Parsen des LLM-JSON aus 'KI: Rechnungstext formatieren'. Bei ungueltigem JSON:
// leerer, aber gueltiger Fallback -> Rechnung wird trotzdem erzeugt, nur mit leeren Feldern.
let data = { positionen: '', leistungstext: '', betrag_gesamt: '' };
try {
  const parsed = JSON.parse($input.first().json.text);
  if (parsed && typeof parsed === 'object') data = { ...data, ...parsed };
} catch (e) { /* ungueltiges LLM-JSON -> Fallback mit leeren Feldern */ }
const quelle = $('Rechnungsdaten sammeln').item.json;
const now = new Date();
const due = new Date(now.getTime() + (quelle.faelligkeit_tage || 14) * 24 * 60 * 60 * 1000);
return [{
  json: {
    rechnungsnummer: 'R-' + now.getFullYear() + '-' + String(now.getTime()).slice(-6),
    datum: now.toISOString().slice(0, 10),
    faelligkeit: due.toISOString().slice(0, 10),
    kunde_name: quelle.kunde_name,
    kunde_email: quelle.kunde_email,
    leistungstext: data.leistungstext || quelle.leistung,
    positionen: data.positionen,
    betrag_gesamt: data.betrag_gesamt || quelle.betrag_hinweis,
  },
}];

// Bestimmt pro offener Rechnung, ob eine neue Mahnstufe faellig ist. Nie mehrfach dieselbe
// Stufe senden; laeuft ueber die Datenablage statt paralleler Wait-Nodes (wie followup-serie).
const rows = ($input.first().json.rows || []);
const now = new Date();
const out = [];
for (const row of rows) {
  const d = row.data || {};
  if (d.status === 'paid' || d.status === 'bezahlt') continue;
  const dueAt = d.due_date ? new Date(d.due_date) : null;
  if (!dueAt || isNaN(dueAt.getTime()) || now < dueAt) continue; // noch nicht faellig
  const daysOverdue = Math.floor((now.getTime() - dueAt.getTime()) / (24 * 60 * 60 * 1000));
  const currentStage = Number(d.mahnstufe || 0);
  let nextStage = currentStage;
  if (currentStage === 0 && daysOverdue >= 0) nextStage = 1;
  else if (currentStage === 1 && daysOverdue >= 7) nextStage = 2;
  else if (currentStage === 2 && daysOverdue >= 14) nextStage = 3;
  if (nextStage === currentStage) continue; // noch keine neue Stufe faellig
  out.push({
    json: {
      row_id: row.id,
      rechnungsnummer: d.rechnungsnummer || row.id,
      stage: nextStage,
      send_target: d.email || d.send_target || '',
      amount: d.amount || '',
      due_date: d.due_date || '',
      customer: d.customer || '',
      days_overdue: daysOverdue,
    },
  });
}
return out;
